import { BrowserRouter, Routes, Route, Navigate, useLocation } from "react-router-dom";
import { useState } from "react";
import HomePage from "./pages/HomePage";
import LoginPage from "./pages/LoginPage";
import RegisterPage from "./pages/RegisterPage";
import EventDetailPage from "./pages/EventDetailPage";
import AppNavbar from "./components/AppNavbar";
import LandingPage from "./pages/LandingPage";
import AdminLayout from "./pages/admin/AdminLayout";
import AdminDashboardPage from "./pages/admin/AdminDashboardPage";
import AdminEventPage from "./pages/admin/AdminEventPage";
import Footer from "./components/Footer";

function AppContent() {
  const location = useLocation();
  const [user, setUser] = useState(
    JSON.parse(localStorage.getItem("user") || "null")
  );

  const isAdmin = user?.role === "admin";
  const isAdminPath = location.pathname.startsWith("/admin");

  return (
    <div style={{ fontFamily: "Inter", minHeight: "100vh", display: "flex", flexDirection: "column" }}>
      {!isAdminPath && <AppNavbar user={user} setUser={setUser} />}

      <main style={{ flex: 1 }}>
        <Routes>
          <Route path="/" element={user ? <HomePage /> : <LandingPage />} />

          <Route
            path="/home"
            element={user ? <HomePage /> : <Navigate to="/login" />}
          />

          <Route
            path="/login"
            element={
              !user ? <LoginPage setUser={setUser} /> : <Navigate to="/home" />
            }
          />

          <Route
            path="/register"
            element={!user ? <RegisterPage /> : <Navigate to="/home" />}
          />

          <Route
            path="/admin"
            element={
              user && isAdmin ? <AdminLayout /> : <Navigate to="/login" />
            }
          >
            <Route index element={<AdminDashboardPage />} />
            <Route path="events" element={<AdminEventPage />} />
          </Route>

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </main>

      {!isAdminPath && <Footer />}
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <AppContent />
    </BrowserRouter>
  );
}

export default App;
